# Subcommand aliases (alias → canonical name)
SUB_ALIASES = {
    "ls": "list",
    "rm": "remove",
    "cp": "copy",
    "mv": "move",
    "rename": "move",
    "init": "config-init",
}
SUBCOMMANDS = [
    "add", "config-init", "copy", "edit", "help",
    "list", "move", "remove", "run", "show",
]
ALL_NAMES = sorted(set(SUBCOMMANDS) | set(SUB_ALIASES.keys()))


def sub_help_long(name):
