# Main entry point
# ────────────────────────────────────────────────────────────────────────

def main(argv):
    verbose = False
    config_file = None
    show_help = False
    show_version = False
    rest = []  # positional args (subcommand + further args)
    i = 0
    while i < len(argv):
        a = argv[i]
        if a == "--":
            i += 1
            while i < len(argv):
                rest.append(argv[i])
                i += 1
            break
        if a in ("-h", "--help"):
            show_help = True
            i += 1
            continue
        if a in ("-V", "--version"):
            show_version = True
            i += 1
            continue
        if a in ("-v", "--verbose"):
            if verbose:
                emit_clap_error(
                    "The argument '--verbose' was provided more than once, but cannot be used multiple times",
                    USAGE_ALIAS_VERBOSE,
                )
            verbose = True
            i += 1
            continue
        if a in ("-c", "--config-file"):
            if i + 1 >= len(argv):
                emit_clap_error(
                    "The argument '--config-file <path>' requires a value but none was supplied",
                    USAGE_MAIN,
                )
            config_file = argv[i + 1]
            i += 2
            continue
        if a.startswith("--config-file=") or a.startswith("-c="):
            config_file = a.split("=", 1)[1]
            i += 1
            continue
        # If it's a flag-looking arg that we don't recognize.
        if a.startswith("--") or (len(a) > 1 and a.startswith("-") and not a[1].isdigit()):
            emit_clap_error(
                f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                USAGE_MAIN,
            )
        # Positional starts.
        rest.append(a)
        i += 1
        while i < len(argv):
            rest.append(argv[i])
            i += 1
        break

    if show_help:
        sys.stdout.write(_H['HELP_LONG'])
        sys.exit(0)
    if show_version:
        sys.stdout.write(f"pier {VERSION}\n")
        sys.exit(0)

    if not rest:
        emit_clap_error(
            "The following required arguments were not provided:\n    <alias>",
            USAGE_MAIN,
        )

    first = rest[0]
    others = rest[1:]

    sub = None
    if first in SUBCOMMANDS:
        sub = first
    elif first in SUB_ALIASES:
        sub = SUB_ALIASES[first]
    if sub:
        dispatch_sub(sub, others, config_file, verbose)
        return

    # Implicit run mode: first arg is alias.
    # But before that, clap checks each remaining arg for "looks like a subcommand?".
    for a in others:
        if a == "--":
            continue
        if a.startswith("-"):
            # Could be unknown flag → clap error.
            emit_clap_error(
                f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                USAGE_MAIN if not verbose else USAGE_ALIAS_VERBOSE,
            )
        sug = did_you_mean(a, ALL_NAMES)
        if sug is not None:
            usage_used = USAGE_MAIN if not verbose else USAGE_ALIAS_VERBOSE
            sys.stderr.write(f"error: The subcommand '{a}' wasn't recognized\n")
            sys.stderr.write(f"\tDid you mean '{sug}'?\n")
            sys.stderr.write(f"\nIf you believe you received this message in error, try re-running with 'executable -- {a}'\n\n")
            sys.stderr.write(usage_used + "\n\nFor more information try --help\n")
            sys.exit(1)

    path, error = get_config_path(config_file)
    if error:
        err(error)
    parsed = load_config(path)
    cmd_run(parsed, {"alias": first, "args": others}, verbose)


def dispatch_sub(sub, rest, config_file, verbose):
    if sub == "help":
        handle_help(rest)
        return
    opts = parse_sub_args(sub, rest)
    if opts.get("__help"):
        sys.stdout.write(_H[f"{sub.replace('-', '')}_long"])
        sys.exit(0)
    if opts.get("__version"):
        sys.stdout.write(SUB_VERSION[sub])
        sys.exit(0)

    if sub == "config-init":
        path = get_init_path(config_file)
        cmd_config_init(path)
        return

    path, error = get_config_path(config_file)
    if error:
        err(error)
    parsed = load_config(path)
    if sub == "list":
        cmd_list(parsed, opts)
    elif sub == "add":
        cmd_add(parsed, opts, path)
    elif sub == "remove":
        cmd_remove(parsed, opts, path)
    elif sub == "show":
        cmd_show(parsed, opts)
    elif sub == "edit":
        cmd_edit(parsed, opts, path)
    elif sub == "run":
        cmd_run(parsed, opts, verbose)
    elif sub == "move":
        cmd_move(parsed, opts, path)
    elif sub == "copy":
        cmd_copy(parsed, opts, path)


def handle_help(rest):
    if not rest:
        sys.stdout.write(_H['HELP_LONG'])
        sys.exit(0)
    name = rest[0]
    canonical = name if name in SUBCOMMANDS else SUB_ALIASES.get(name)
    if canonical is None or canonical == "help":
        if name == "help":
            sys.stdout.write(_H['help_help_long'])
            sys.exit(0)
        sys.stderr.write(
            f"error: The subcommand '{name}' wasn't recognized\n\n"
            "USAGE:\n\texecutable help <subcommands>...\n\n"
            "For more information try --help\n"
        )
        sys.exit(1)
    sys.stdout.write(_H[f"{canonical.replace('-', '')}_long"])
    sys.exit(0)


def parse_sub_args(sub, args):
    opts = {}
    pos = []
    i = 0
    end_of_options = False
    while i < len(args):
        a = args[i]
        if end_of_options:
            pos.append(a)
            i += 1
            continue
        if a == "--":
            end_of_options = True
            i += 1
            continue
        if a in ("-h", "--help"):
            opts["__help"] = True
            i += 1
            continue
        if a in ("-V", "--version"):
            opts["__version"] = True
            i += 1
            continue

        if sub == "add":
            if a in ("-f", "--force"):
                opts["force"] = True
                i += 1
                continue
            if a in ("-a", "--alias"):
                if i + 1 >= len(args):
                    emit_clap_error(
                        "The argument '--alias <alias>' requires a value but none was supplied",
                        SUB_USAGE["add"],
                    )
                opts["alias"] = args[i + 1]
                i += 2
                continue
            if a.startswith("--alias="):
                opts["alias"] = a.split("=", 1)[1]
                i += 1
                continue
            if a in ("-d", "--description"):
                if i + 1 >= len(args):
                    emit_clap_error(
                        "The argument '--description <description>' requires a value but none was supplied",
                        SUB_USAGE["add"],
                    )
                opts["description"] = args[i + 1]
                i += 2
                continue
            if a.startswith("--description="):
                opts["description"] = a.split("=", 1)[1]
                i += 1
                continue
            if a in ("-t", "--tag"):
                tags = opts.setdefault("tags", [])
                i += 1
                if i >= len(args):
                    emit_clap_error(
                        "The argument '--tag <tags>...' requires a value but none was supplied",
                        SUB_USAGE["add"],
                    )
                while i < len(args) and not args[i].startswith("-") and args[i] != "--":
                    tags.append(args[i])
                    i += 1
                continue
            if a.startswith("-"):
                emit_clap_error(
                    f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                    SUB_USAGE["add"],
                )
            pos.append(a)
            i += 1
            continue

        if sub == "list":
            if a in ("-l", "--cmd_full"):
                opts["cmd_full"] = True
                i += 1
                continue
            if a in ("-q", "--list_aliases"):
                opts["list_aliases"] = True
                i += 1
                continue
            if a in ("-c", "--cmd_width"):
                if i + 1 >= len(args):
                    emit_clap_error(
                        "The argument '--cmd_width <cmd-width>' requires a value but none was supplied",
                        "USAGE:\n    executable list --cmd_width <cmd-width>",
                    )
                val = args[i + 1]
                try:
                    opts["cmd_width"] = int(val)
                except ValueError:
                    sys.stderr.write(
                        "error: Invalid value for '--cmd_width <cmd-width>': invalid digit found in string\n"
                    )
                    sys.exit(1)
                i += 2
                continue
            if a.startswith("--cmd_width="):
                try:
                    opts["cmd_width"] = int(a.split("=", 1)[1])
                except ValueError:
                    sys.stderr.write(
                        "error: Invalid value for '--cmd_width <cmd-width>': invalid digit found in string\n"
                    )
                    sys.exit(1)
                i += 1
                continue
            if a in ("-t", "--tag"):
                tags = opts.setdefault("tags", [])
                i += 1
                if i >= len(args):
                    emit_clap_error(
                        "The argument '--tag <tags>...' requires a value but none was supplied",
                        "USAGE:\n    executable list --tag <tags>...",
                    )
                while i < len(args) and not args[i].startswith("-") and args[i] != "--":
                    tags.append(args[i])
                    i += 1
                continue
            if a.startswith("-"):
                emit_clap_error(
                    f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                    SUB_USAGE["list"],
                )
            pos.append(a)
            i += 1
            continue

        if sub in ("remove", "show", "edit"):
            if a.startswith("-"):
                emit_clap_error(
                    f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                    SUB_USAGE[sub],
                )
            pos.append(a)
            i += 1
            continue

        if sub == "run":
            if a.startswith("-") and not pos:
                emit_clap_error(
                    f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                    SUB_USAGE["run"],
                )
            pos.append(a)
            i += 1
            while i < len(args):
                if args[i] == "--":
                    i += 1
                    continue
                pos.append(args[i])
                i += 1
            continue

        if sub in ("move", "copy"):
            if a in ("-f", "--force"):
                if sub == "copy":
                    emit_clap_error(
                        f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                        SUB_USAGE["copy"],
                    )
                opts["force"] = True
                i += 1
                continue
            if a.startswith("-"):
                emit_clap_error(
                    f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                    SUB_USAGE[sub],
                )
            pos.append(a)
            i += 1
            continue

        if sub == "config-init":
            if a.startswith("-"):
                emit_clap_error(
                    f"Found argument '{a}' which wasn't expected, or isn't valid in this context",
                    SUB_USAGE["config-init"],
                )
            pos.append(a)
            i += 1
            continue

        pos.append(a)
        i += 1

    if opts.get("__help") or opts.get("__version"):
        return opts

    if sub == "add":
        if "alias" not in opts:
            emit_clap_error(
                "The following required arguments were not provided:\n    --alias <alias>",
                SUB_USAGE["add"],
            )
        if len(pos) > 1:
            emit_clap_error(
                f"Found argument '{pos[1]}' which wasn't expected, or isn't valid in this context",
                SUB_USAGE["add"],
            )
        if pos:
            opts["command"] = pos[0]
        return opts
    if sub == "remove":
        if not pos:
            emit_clap_error(
                "The following required arguments were not provided:\n    <alias>",
                SUB_USAGE["remove"],
            )
        if len(pos) > 1:
            emit_clap_error(
                f"Found argument '{pos[1]}' which wasn't expected, or isn't valid in this context",
                SUB_USAGE["remove"],
            )
        opts["alias"] = pos[0]
        return opts
    if sub == "show":
        if not pos:
            emit_clap_error(
                "The following required arguments were not provided:\n    <alias>",
                SUB_USAGE["show"],
            )
        if len(pos) > 1:
            emit_clap_error(
                f"Found argument '{pos[1]}' which wasn't expected, or isn't valid in this context",
                SUB_USAGE["show"],
            )
        opts["alias"] = pos[0]
        return opts
    if sub == "edit":
        if not pos:
            emit_clap_error(
                "The following required arguments were not provided:\n    <alias>",
                SUB_USAGE["edit"],
            )
        if len(pos) > 1:
            emit_clap_error(
                f"Found argument '{pos[1]}' which wasn't expected, or isn't valid in this context",
                SUB_USAGE["edit"],
            )
        opts["alias"] = pos[0]
        return opts
    if sub == "run":
        if not pos:
            emit_clap_error(
                "The following required arguments were not provided:\n    <alias>",
                SUB_USAGE["run"],
            )
        opts["alias"] = pos[0]
        opts["args"] = pos[1:]
        return opts
    if sub in ("move", "copy"):
        missing = []
        if len(pos) < 1:
            missing.append("<from-alias>")
        if len(pos) < 2:
            missing.append("<to-alias>")
        if missing:
            emit_clap_error(
                "The following required arguments were not provided:\n    " + "\n    ".join(missing),
                SUB_USAGE[sub],
            )
        if len(pos) > 2:
            emit_clap_error(
                f"Found argument '{pos[2]}' which wasn't expected, or isn't valid in this context",
                SUB_USAGE[sub],
            )
        opts["from"] = pos[0]
        opts["to"] = pos[1]
        return opts
    if sub == "config-init":
        if pos:
            emit_clap_error(
                f"Found argument '{pos[0]}' which wasn't expected, or isn't valid in this context",
                SUB_USAGE["config-init"],
            )
        return opts
    return opts


