    """toml-rs style:
    - contains '\n' → triple-single literal with leading newline
    - else if contains single quote and no double quote → double-quoted basic
    - else if contains both single and double quote → triple-single literal (no leading nl)
    - else → single-quoted literal
    """
    has_nl = "\n" in s
    has_sq = "'" in s
    has_dq = '"' in s
    if has_nl:
        return "'''\n" + s + "'''"
    if has_sq and not has_dq:
