#!/usr/bin/env python3
"""Randomized usage-Markov-chain fuzzer comparing ref and sut."""
import os, shutil, subprocess, random, sys

REF = "/workspace/executable"
SUT = "/work/work/executable"
ROOT = "/tmp/fuzz"
SEED = int(os.environ.get("SEED", "42"))
NUM = int(os.environ.get("NUM", "100"))

random.seed(SEED)

passed = 0
failed = 0
failures = []


def setup_clean():
    if os.path.exists(ROOT):
        shutil.rmtree(ROOT)
    os.makedirs(ROOT)


def cfg_path():
    return os.path.join(ROOT, "p.toml")


def snap():
    p = cfg_path()
    if not os.path.exists(p):
        return None
    with open(p, "rb") as f:
        return f.read()


def run_binary(binary, args, env):
    full_env = dict(os.environ)
    for k in ("PIER_CONFIG_PATH", "XDG_CONFIG_HOME", "HOME", "EDITOR", "SHELL"):
        full_env.pop(k, None)
    full_env.update(env)
    try:
        p = subprocess.run(
            [binary] + args, env=full_env, cwd=ROOT,
            capture_output=True, timeout=10,
        )
        return p.returncode, p.stdout, p.stderr
    except subprocess.TimeoutExpired:
        return -999, b"TIMEOUT", b""


def step(seq, initial_toml=None):
    """Run a sequence of commands on both ref and sut, comparing each step.
    seq is a list of (env_overrides, args)."""
    global passed, failed
    name = " ".join(str(a) for _, a in seq)

    def run_seq(binary):
        setup_clean()
        if initial_toml is not None:
            with open(cfg_path(), "w") as f:
                f.write(initial_toml)
        outs = []
        for env, args in seq:
            full = {"PIER_CONFIG_PATH": cfg_path(), **env}
            rc, so, se = run_binary(binary, args, full)
            outs.append((rc, so, se, snap()))
        return outs

    ref_outs = run_seq(REF)
    sut_outs = run_seq(SUT)
    if ref_outs == sut_outs:
        passed += 1
    else:
        failed += 1
        failures.append(name)
        print(f"FAIL: [{name}]")
        for i, (rr, ss) in enumerate(zip(ref_outs, sut_outs)):
            if rr != ss:
                print(f"  step {i} args={seq[i][1]}")
                if rr[0] != ss[0]:
                    print(f"    exit ref={rr[0]} sut={ss[0]}")
                if rr[1] != ss[1]:
                    print(f"    stdout ref={rr[1]!r}")
                    print(f"           sut={ss[1]!r}")
                if rr[2] != ss[2]:
                    print(f"    stderr ref={rr[2]!r}")
                    print(f"           sut={ss[2]!r}")
                if rr[3] != ss[3]:
                    print(f"    config ref={rr[3]!r}")
                    print(f"           sut={ss[3]!r}")


ALIASES = ["foo", "bar", "baz", "hello-pier", "x", "abc"]
COMMANDS = ["echo a", "echo b", "exit 0", "true", "false", "echo $1", "echo done"]
TAGS = ["dev", "test", "ops", "ci"]
DESCS = ["first", "second", "third"]


def gen_add():
    args = ["add", "-a", random.choice(ALIASES)]
    if random.random() < 0.3:
        args.append("-f")
    if random.random() < 0.3:
        args.extend(["-d", random.choice(DESCS)])
    if random.random() < 0.3:
        args.extend(["-t", random.choice(TAGS)])
    if random.random() < 0.2:
        args.extend(["-t", random.choice(TAGS), random.choice(TAGS)])
    args.append("--")
    args.append(random.choice(COMMANDS))
    return args


def gen_remove():
    return ["remove", random.choice(ALIASES)]


def gen_show():
    return ["show", random.choice(ALIASES)]


def gen_list():
    args = ["list"]
    if random.random() < 0.3:
        args.append("-l")
    if random.random() < 0.3:
        args.append("-q")
    if random.random() < 0.3:
        args.extend(["-c", str(random.randint(1, 80))])
    if random.random() < 0.3:
        args.extend(["-t", random.choice(TAGS)])
    return args


def gen_run():
    args = ["run", random.choice(ALIASES)]
    if random.random() < 0.3:
        args.append("arg1")
    return args


def gen_move():
    return ["move", random.choice(ALIASES), random.choice(ALIASES)]


def gen_copy():
    return ["copy", random.choice(ALIASES), random.choice(ALIASES)]


def gen_implicit():
    return [random.choice(ALIASES)]


def gen_op():
    return random.choice([
        gen_add, gen_remove, gen_show, gen_list, gen_run,
        gen_move, gen_copy, gen_implicit,
    ])()


INIT = '[scripts.hello-pier]\ncommand = '"'"'echo Hello, Pier!'"'"'\n\n[default]\n'

for i in range(NUM):
    # short random sequence
    seq_len = random.randint(1, 4)
    seq = []
    for _ in range(seq_len):
        env = {}
        if random.random() < 0.2:
            env["EDITOR"] = "true"
        args = gen_op()
        if random.random() < 0.3:
            args.insert(0, "-v")
        seq.append((env, args))
    step(seq, initial_toml=INIT)

print()
print(f"Fuzz Summary: {passed}/{passed+failed} passed, {failed} failed")
if failures:
    print("Sample failures:", failures[:5])

